
import React, { useState, useEffect } from "react";


import { CloseModal, OpenModal } from "../../../components/DialogHRM";
import {  SvgIcon_Cmpt, TextInput_Cmpt, SearchInput_Cmpt, DropDwnSearchPicker_Cmpt, CheckBoxSlide_Cmpt, LoadingColorSpinner_Cmpt } from "../../../components";
import { updStore, getStore, gen16CodeId, ObjectKeys, qryKprofile, qryKClient, parseDate, parseDateMMDDYYYY, txtOrempty, compareJSON, 
	

	getExtFile, isImageFile, getExtFileType,
	fetchEncryptStream, _monthNames, qryStore, b64toUrl } from "../../../stores/Utils";

import DateCalComponent from "./DateCalComponent";
import {  generateTranslateBirthCertification, generateNewBirthCertification } from "../services/print_service";
import { search_notaryAgent, sortByName, getById_notary, handleFetchImage, getSignedUploadUrl, uploadSignedUrl, get_print_structure } from "../services/customer_fetch_service";
import { TextOnImageBTC_Cmpt } from "..";



const TextInput = TextInput_Cmpt();


const Svg = SvgIcon_Cmpt();


const DropDwnSearchPicker = DropDwnSearchPicker_Cmpt();

const TextOnImage = TextOnImageBTC_Cmpt();



const CheckBoxSlide = CheckBoxSlide_Cmpt();


const LoadingColorSpinner = LoadingColorSpinner_Cmpt();







